# checkers.py

class Board:
    """
    Manages the state of the board.
    """
    def __init__(self):
        self.grid = [[None for _ in range(8)] for _ in range(8)]
        self.setup_board()

    def setup_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range(0, 8, 2):
                self.grid[i][j] = Piece('red')
        for i in range(5, 8):
            for j in range(1, 9, 2):
                self.grid[i][j] = Piece('black')

    def print_board(self):
        # Print the current state of the board
        for row in self.grid:
            print(" ".join([str(piece) if piece else 'E' for piece in row]))

class Piece:
    """
    Represents a piece on the board.
    """
    def __init__(self, color, king=False):
        self.color = color
        self.king = king

    def __str__(self):
        if self.color == 'red':
            return 'R' if not self.king else 'K'
        elif self.color == 'black':
            return 'B' if not self.king else 'k'
        return 'E'

class Move:
    """
    Represents a move made by a player.
    """
    def __init__(self, from_pos, to_pos):
        self.from_pos = from_pos
        self.to_pos = to_pos

class Game:
    """
    Manages the game logic, turn-taking, and rules enforcement.
    """
    def __init__(self):
        self.board = Board()
        self.current_player = 'red'

    def switch_player(self):
        # Switch the current player
        if self.current_player == 'red':
            self.current_player = 'black'
        else:
            self.current_player = 'red'

    def make_move(self, move):
        # Make a move on the board
        piece = self.board.grid[move.from_pos[0]][move.from_pos[1]]
        if piece and piece.color == self.current_player:
            self.board.grid[move.to_pos[0]][move.to_pos[1]] = piece
            self.board.grid[move.from_pos[0]][move.from_pos[1]] = None
            self.switch_player()

# game_manager.py

from checkers import Game, Board, Move

class GameManager:
    """
    Manages the game state and user interactions.
    """
    def __init__(self):
        self.game = Game()
        self.board = self.game.board

    def run(self):
        while True:
            self.board.print_board()
            from_pos = input(f"{self.game.current_player.capitalize()}, enter your move (from-to): ").split('-')
            to_pos = [int(from_pos[0][1]), int(from_pos[0][3])]
            move = Move((to_pos[0], to_pos[1]))
            self.game.make_move(move)

# server.py

from game_manager import GameManager

def run():
    """
    This is the main module to launch the program.
    """
    manager = GameManager()
    manager.run()

if __name__ == "__main__":
    run()
